"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["8593"],{4030(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>p,frontMatter:()=>t,contentTitle:()=>r,toc:()=>l,assets:()=>c});var o=JSON.parse('{"id":"Planets & Points/Ascendant","title":"Ascendant","description":"Principle:","source":"@site/docs/Planets & Points/Ascendant.md","sourceDirName":"Planets & Points","slug":"/Planets & Points/Ascendant","permalink":"/Planets & Points/Ascendant","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Planets & Points/Ascendant.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"uranus-ceres","permalink":"/Midpoints/Venus/uranus-ceres"},"next":{"title":"Jupiter","permalink":"/Planets & Points/Jupiter"}}'),a=i(4848),s=i(8453);let t={},r,c={},l=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"The Personality. (Environment)."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The psychological colouring of the Ascendant depends upon its zodiacal sign."}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The moment of birth. \u2013 The reaction to the world outside or the environment in general."}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The Ego in relationship with other people, particularly with persons of the environment."}),"\n",(0,a.jsx)(n.p,{children:"Position in the Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. A restless environment with energetic or industrious people. \u2013 The power to obtain and to maintain one's place in the world, self-confidence, ambition, conscious concentration upon a desired aim or objective, impulsiveness, a passionate mode of expression. \u2013 Fanaticism, ruthlessness, rashness, quarrelsomeness."}),"\n",(0,a.jsx)(n.p,{children:"II. A beautiful and quiet environment, real estate and land-ownership, secure circumstances. \u2013 Steadfastness, firmness, domesticity. Paying attention to the practicalities of life, the ability to create a homely atmosphere, a love of pompous display. \u2013 Egotism, the craving for enjoyment and indulgence, obstinacy, avarice."}),"\n",(0,a.jsx)(n.p,{children:"III. A lively and versatile environment with many social contacts. \u2013 An obliging manner, a quick response to influences from the environment, adaptation, mobility, good comprehension, talkatiousness. \u2013 Superficiality, inconstancy, boastfulness."}),"\n",(0,a.jsx)(n.p,{children:"IV. The dependence on moods, a rich home-life within the family-circle, moist and humid regions, simple and humble circumstances. \u2013 A caring, sympathetic and dedicated nature, impressionability, the desire to lean on other people, industriousness. \u2013 Moodiness, the inability to stand on one's own feet, (sensitiveness and) hyper-sensitiveness."}),"\n",(0,a.jsx)(n.p,{children:"V. An impressive personality, a luxurious environment. \u2013 An authoritative, self-confident and dignified manner, generosity, justice and fair play, open-mindedness and frankness, love of splendour, the joy of living. \u2013 Haughtiness, the craving for adventure, self-glorification."}),"\n",(0,a.jsx)(n.p,{children:"VI. Stable conditions and circumstances. \u2013 Reserve, a critical attitude, caution, observation, thoroughness, care and attention, simplicity, tidiness. \u2013 Fuss, pedantry, prejudice."}),"\n",(0,a.jsx)(n.p,{children:"VII. Harmonious establishment of the home. \u2013 An affectionate nature, liveliness, good manners, the desire to lean on somebody. \u2013 An easy-going and playful nature, aversion to hard or dirty work, vanity, the craving for applause."}),"\n",(0,a.jsx)(n.p,{children:"VIII. A disharmonious and aggressive environment, humid regions. \u2013 Reserve, caution, readiness for action, the power of quick decision, zeal, industry. \u2013 The preservation of the species, passionateness, violence, sudden wrath, fanaticism."}),"\n",(0,a.jsx)(n.p,{children:"IX. A social or religious person with great and far-reaching aims. \u2013 Liveliness, dependence on moods, enthusiasm, sociableness, love of nature, sport- and outdoor-activity. \u2013 The desire for recognition, the love of adventure, sentimentality."}),"\n",(0,a.jsx)(n.p,{children:'X. A purposeful attitude and the tendency to act according to expediency. \u2013 Self-willedness, tenacity, industry, self-control, concentration, diplomacy, a responsible attitude. "Actions say more than words". \u2013 Inhibitions, shyness, egotism.'}),"\n",(0,a.jsx)(n.p,{children:"XI. An environment keyed to reform ideas. \u2013 One's own ideas, a knowledge of human nature, the desire for innovations, far-reaching interests, adaptability, an intense soul-life. \u2013 Changes of mood, small measure of endurance, changing objectives."}),"\n",(0,a.jsx)(n.p,{children:"XII. A peculiar, lonely and simple person. \u2013 Reserve, inhibition, timidity, a passive and inactive nature, abundance of feeling, the tendency to become depressed. \u2013 Instability, vagueness, comfort and laziness."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"ASCENDENT"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Osobowo\u015B\u0107. (Otoczenie)."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Psychologiczne zabarwienie Ascendentu zale\u017Cy od jego znaku zodiaku."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Moment narodzin. \u2013 Reakcja na \u015Bwiat zewn\u0119trzny lub og\xf3lnie na otoczenie."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Ego w relacji z innymi lud\u017Ami, w szczeg\xf3lno\u015Bci z osobami z otoczenia."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Niespokojne otoczenie z energicznymi lub pracowitymi lud\u017Ami. \u2013 Si\u0142a do zdobycia i utrzymania swojego miejsca w \u015Bwiecie, pewno\u015B\u0107 siebie, ambicja, \u015Bwiadoma koncentracja na upragnionym celu lub d\u0105\u017Ceniu, impulsywno\u015B\u0107, nami\u0119tny spos\xf3b wyra\u017Cania si\u0119. \u2013 Fanatyzm, bezwzgl\u0119dno\u015B\u0107, lekkomy\u015Blno\u015B\u0107, k\u0142\xf3tlizwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"II. Pi\u0119kne i ciche otoczenie, nieruchomo\u015Bci i w\u0142asno\u015B\u0107 ziemska, bezpieczne warunki. \u2013 Niez\u0142omno\u015B\u0107, stanowczo\u015B\u0107, przywi\u0105zanie do ogniska domowego. Zwracanie uwagi na praktyczne strony \u017Cycia, zdolno\u015B\u0107 do tworzenia domowej atmosfery, zami\u0142owanie do wystawnego (pompatycznego) popisywania si\u0119. \u2013 Egotyzm, \u0142aknienie przyjemno\u015Bci i pob\u0142a\u017Cania sobie, uparto\u015B\u0107, chciwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"III. \u017Bywe i wszechstronne otoczenie z wieloma kontaktami towarzyskimi. \u2013 Us\u0142u\u017Cny spos\xf3b bycia, szybkie reagowanie na wp\u0142ywy z otoczenia, adaptacja, mobilno\u015B\u0107, dobre pojmowanie, gadatliwo\u015B\u0107. \u2013 Powierzchowno\u015B\u0107, niesta\u0142o\u015B\u0107, przechwalanie si\u0119."}),"\n",(0,a.jsx)(n.p,{children:"IV. Zale\u017Cno\u015B\u0107 od nastroj\xf3w, bogate \u017Cycie domowe w kr\u0119gu rodziny, wilgotne i podmok\u0142e regiony, proste i skromne warunki. \u2013 Troskliwa, pe\u0142na empatii i oddana natura, podatno\u015B\u0107 na wra\u017Cenia, pragnienie oparcia si\u0119 na innych ludziach, pracowito\u015B\u0107. \u2013 Humorzasto\u015B\u0107, niezdolno\u015B\u0107 do stani\u0119cia na w\u0142asnych nogach, (wra\u017Cliwo\u015B\u0107 i) nadwra\u017Cliwo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"V. Imponuj\u0105ca osobowo\u015B\u0107, luksusowe otoczenie. \u2013 Autorytatywny, pewny siebie i pe\u0142en godno\u015Bci spos\xf3b bycia, wielkoduszno\u015B\u0107, sprawiedliwo\u015B\u0107 i uczciwa gra (fair play), otwarto\u015B\u0107 umys\u0142u i szczero\u015B\u0107, zami\u0142owanie do przepychu, rado\u015B\u0107 \u017Cycia. \u2013 Wynios\u0142o\u015B\u0107, \u0142aknienie przyg\xf3d, samouwielbienie."}),"\n",(0,a.jsx)(n.p,{children:"VI. Stabilne warunki i okoliczno\u015Bci. \u2013 Rezerwa, krytyczna postawa, ostro\u017Cno\u015B\u0107, obserwacja, dok\u0142adno\u015B\u0107, troska i uwaga, prostota, porz\u0105dek. \u2013 Zamieszanie (zbytnia przej\u0119to\u015B\u0107), pedanteria, uprzedzenia."}),"\n",(0,a.jsx)(n.p,{children:"VII. Harmonijne urz\u0105dzenie domu. \u2013 Czu\u0142a natura, \u017Cywio\u0142owo\u015B\u0107, dobre maniery, pragnienie oparcia si\u0119 na kim\u015B. \u2013 \u0141atwowierny (wyluzowany) i zabawowy charakter, awersja do ci\u0119\u017Ckiej lub brudnej pracy, pr\xf3\u017Cno\u015B\u0107, \u0142aknienie poklasku."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Dysharmonijne i agresywne otoczenie, wilgotne regiony. \u2013 Rezerwa, ostro\u017Cno\u015B\u0107, gotowo\u015B\u0107 do dzia\u0142ania, zdolno\u015B\u0107 szybkiego podejmowania decyzji, gorliwo\u015B\u0107, pracowito\u015B\u0107. \u2013 Podtrzymanie gatunku, nami\u0119tno\u015B\u0107, przemoc, nag\u0142y gniew, fanatyzm."}),"\n",(0,a.jsx)(n.p,{children:"IX. Osoba spo\u0142eczna lub religijna o wielkich i dalekosi\u0119\u017Cnych celach. \u2013 \u017Bywio\u0142owo\u015B\u0107, zale\u017Cno\u015B\u0107 od nastroj\xf3w, entuzjazm, towarzysko\u015B\u0107, mi\u0142o\u015B\u0107 do natury, aktywno\u015B\u0107 sportowa i na \u015Bwie\u017Cym powietrzu. \u2013 Pragnienie uznania, zami\u0142owanie do przyg\xf3d, sentymentalizm."}),"\n",(0,a.jsx)(n.p,{children:"X. Celowa postawa i tendencja do dzia\u0142ania zgodnie z korzy\u015Bci\u0105 (celowo\u015Bci\u0105). \u2013 Uparto\u015B\u0107 (samowola), nieust\u0119pliwo\u015B\u0107, pracowito\u015B\u0107, samokontrola, koncentracja, dyplomacja, odpowiedzialna postawa. \u201ECzyny m\xf3wi\u0105 wi\u0119cej ni\u017C s\u0142owa\u201D. \u2013 Zahamowania, nie\u015Bmia\u0142o\u015B\u0107, egotyzm."}),"\n",(0,a.jsx)(n.p,{children:"XI. Otoczenie nastrojone na idee reformatorskie. \u2013 W\u0142asne pomys\u0142y, znajomo\u015B\u0107 natury ludzkiej, pragnienie innowacji, dalekosi\u0119\u017Cne zainteresowania, zdolno\u015B\u0107 adaptacji, intensywne \u017Cycie duszy. \u2013 Zmiany nastroju, niewielka miara wytrwa\u0142o\u015Bci, zmieniaj\u0105ce si\u0119 cele."}),"\n",(0,a.jsx)(n.p,{children:"XII. Osobliwa, samotna i prosta osoba. \u2013 Rezerwa, zahamowanie, boja\u017Aliwo\u015B\u0107, pasywna i nieaktywna natura, obfito\u015B\u0107 uczu\u0107, tendencja do popadania w przygn\u0119bienie. \u2013 Niestabilno\u015B\u0107, mglisto\u015B\u0107, wygoda i lenistwo."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>r});var o=i(6540);let a={},s=o.createContext(a);function t(e){let n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:t(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);